94	    public StudentProfileEntity createStudent(StudentCreateRequest request) {
95	        StudentProfileEntity entity = new StudentProfileEntity();
96	        entity.setStudentNo(request.studentNo());
97	        entity.setFirstName(request.firstName());
98	        entity.setLastName(request.lastName());
99	        entity.setPreferredName(request.preferredName());
100	        entity.setDateOfBirth(request.dateOfBirth());
101	        entity.setStatus("ACTIVE");
102	        entity.setContactEmail(request.contactEmail());
103	        entity.setContactPhone(request.contactPhone());
104	        entity.setContactAddress(request.contactAddress());
105	        entity.setEmergencyContact(request.emergencyContact());
106	        entity.setMaskedEmail(maskEmail(request.contactEmail()));
107	        entity.setMaskedPhone(maskPhone(request.contactPhone()));
108	        StudentProfileEntity saved = studentProfileRepository.save(entity);
109	        governanceAuditService.recordChange("STUDENT", saved.getId(), "CREATE", null, studentSnapshot(saved), "MANUAL_CREATE");
