114	        if (!StringUtils.hasText(query)) {
115	            return studentProfileRepository.findByDeletedAtIsNullOrderByLastNameAscFirstNameAsc();
116	        }
117	        return studentProfileRepository.findByDeletedAtIsNullAndFirstNameContainingIgnoreCaseOrDeletedAtIsNullAndLastNameContainingIgnoreCase(query, query);
