120	    public List<StudentProfileEntity> searchStudentsForPrincipal(Authentication authentication, String query) {
121	        if (!isStudentPrincipal(authentication)) {
122	            return searchStudents(query);
123	        }
124	        StudentProfileEntity mine = resolveStudentForPrincipal(authentication);
125	        if (!StringUtils.hasText(query)) {
126	            return List.of(mine);
127	        }
128	        String q = query.trim().toLowerCase(Locale.ROOT);
129	        String fullName = (mine.getFirstName() + " " + mine.getLastName()).toLowerCase(Locale.ROOT);
130	        if (mine.getStudentNo().toLowerCase(Locale.ROOT).contains(q) || fullName.contains(q)) {
131	            return List.of(mine);
132	        }
133	        return List.of();
134	    }
