141	        }
142	        StudentProfileEntity student = findActiveStudent(studentId);
143	        String oldStatus = student.getStatus();
144	        student.setStatus(normalized);
145	        StudentProfileEntity saved = studentProfileRepository.save(student);
146	        governanceAuditService.recordChange(
147	            "STUDENT",
