260	    @Transactional
261	    public HomeworkAttachmentRecordEntity uploadHomework(Long studentId, HomeworkUploadRequest request, MultipartFile file) {
262	        findActiveStudent(studentId);
263	        if (file == null || file.isEmpty()) {
264	            throw new IllegalArgumentException("Homework file is required");
265	        }
266	        if (file.getSize() > MAX_FILE_SIZE) {
267	            throw new IllegalArgumentException("File exceeds 10MB limit");
268	        }
269	
270	        String mimeType = normalizeMimeType(file.getContentType());
271	        String originalName = StringUtils.cleanPath(Optional.ofNullable(file.getOriginalFilename()).orElse("upload"));
272	        String extension = extensionOf(originalName);
273	        validateFileType(mimeType, extension);
274	
275	        String computedChecksum = sha256Hex(file);
276	        if (StringUtils.hasText(request.expectedChecksum()) && !computedChecksum.equalsIgnoreCase(request.expectedChecksum())) {
277	            throw new IllegalArgumentException("Checksum mismatch");
278	        }
279	
280	        try {
281	            Path studentDir = uploadRoot.resolve("homework").resolve(String.valueOf(studentId));
282	            Files.createDirectories(studentDir);
283	            String storedName = UUID.randomUUID() + extension;
284	            Path target = studentDir.resolve(storedName).normalize();
285	            Files.copy(file.getInputStream(), target, StandardCopyOption.REPLACE_EXISTING);
286	
287	            HomeworkAttachmentRecordEntity entity = new HomeworkAttachmentRecordEntity();
288	            entity.setStudentId(studentId);
289	            entity.setClassId(request.classId());
290	            entity.setClassSessionId(request.classSessionId());
291	            entity.setOriginalFileName(originalName);
292	            entity.setStoredFileName(storedName);
293	            entity.setMimeType(mimeType);
294	            entity.setFileSizeBytes(file.getSize());
295	            entity.setSha256Checksum(computedChecksum);
296	            entity.setUploadPath(target.toString());
297	            entity.setUploadedBy(currentUserId());
298	            entity.setUploadedAt(LocalDateTime.now());
299	            return homeworkAttachmentRecordRepository.save(entity);
300	        } catch (IOException ex) {
301	            throw new IllegalStateException("Unable to persist homework attachment", ex);
302	        }
303	    }
