378	    public boolean canUnmask(Authentication authentication) {
379	        if (authentication == null) {
380	            return false;
381	        }
382	        return authentication.getAuthorities().stream()
383	            .map(GrantedAuthority::getAuthority)
384	            .anyMatch(role -> "ROLE_SYSTEM_ADMIN".equals(role) || "ROLE_REGISTRAR_FINANCE_CLERK".equals(role));
385	    }
