456	    private StudentProfileEntity resolveStudentForPrincipal(Authentication authentication) {
457	        if (authentication == null || !authentication.isAuthenticated()) {
458	            throw new AccessDeniedException("Authentication required");
459	        }
460	        if (!StringUtils.hasText(authentication.getName())) {
461	            throw new AccessDeniedException("No principal username is available");
462	        }
463	        return studentProfileLookupRepository.findByStudentNoIgnoreCaseAndDeletedAtIsNull(authentication.getName())
464	            .orElseThrow(() -> new AccessDeniedException("No student profile is bound to principal " + authentication.getName()));
465	    }
