467	    private static boolean isStudentPrincipal(Authentication authentication) {
468	        if (authentication == null) {
469	            return false;
470	        }
471	        return authentication.getAuthorities().stream().map(GrantedAuthority::getAuthority).anyMatch("ROLE_STUDENT"::equals);
472	    }
