474	    private static boolean hasAnyRole(Authentication authentication, String... roles) {
475	        if (authentication == null) {
476	            return false;
477	        }
478	        Set<String> granted = authentication.getAuthorities().stream().map(GrantedAuthority::getAuthority).collect(java.util.stream.Collectors.toSet());
479	        for (String role : roles) {
480	            if (granted.contains(role)) {
481	                return true;
482	            }
483	        }
484	        return false;
485	    }
