487	    private boolean instructorCanAccessStudent(Long instructorUserId, Long studentId) {
488	        Integer count = jdbcTemplate.queryForObject(
489	            """
490	                SELECT COUNT(*)
491	                FROM enrollments e
492	                JOIN classes c ON c.id = e.class_id
493	                WHERE e.student_id = ?
494	                  AND e.deleted_at IS NULL
495	                  AND e.enrollment_status IN ('ENROLLED', 'WAITLISTED', 'COMPLETED')
496	                  AND c.instructor_user_id = ?
497	            """,
498	            Integer.class,
499	            studentId,
500	            instructorUserId
501	        );
502	        return count != null && count > 0;
503	    }
