527	    private static String maskPhone(String phone) {
528	        if (!StringUtils.hasText(phone)) {
529	            return null;
530	        }
531	        String normalized = phone.replaceAll("\\D", "");
532	        if (normalized.length() <= 4) {
533	            return "****";
534	        }
535	        return "***-***-" + normalized.substring(normalized.length() - 4);
536	    }
