559	    private static String normalizeMimeType(String raw) {
560	        if (!StringUtils.hasText(raw)) {
561	            return "";
562	        }
563	        return raw.trim().toLowerCase(Locale.ROOT);
564	    }
565	
566	    private static String extensionOf(String fileName) {
567	        int idx = fileName.lastIndexOf('.');
568	        if (idx < 0) {
569	            return "";
570	        }
571	        return fileName.substring(idx).toLowerCase(Locale.ROOT);
572	    }
