574	    private static void validateFileType(String mimeType, String extension) {
575	        boolean pdf = "application/pdf".equals(mimeType) && ".pdf".equals(extension);
576	        boolean jpg = "image/jpeg".equals(mimeType) && (".jpg".equals(extension) || ".jpeg".equals(extension));
577	        if (!pdf && !jpg) {
578	            throw new IllegalArgumentException("Only PDF and JPG homework attachments are allowed");
579	        }
580	    }
