8	import org.springframework.stereotype.Service;
9	import org.springframework.transaction.annotation.Transactional;
10	
11	@Service
12	public class AuditLogService {
13	
14	    private final OperationLogRepository operationLogRepository;
15	    private final DataAccessLogRepository dataAccessLogRepository;
16	
17	    public AuditLogService(
18	        OperationLogRepository operationLogRepository,
19	        DataAccessLogRepository dataAccessLogRepository
20	    ) {
21	        this.operationLogRepository = operationLogRepository;
22	        this.dataAccessLogRepository = dataAccessLogRepository;
23	    }
24	
25	    @Transactional
26	    public void logOperation(
27	        Long actorUserId,
28	        String actorUsername,
29	        String roleSnapshot,
30	        String action,
31	        String entityType,
32	        Long entityId,
33	        String requestId,
34	        String clientIp,
35	        boolean success,
36	        String message
37	    ) {
38	        OperationLogEntity entry = new OperationLogEntity();
39	        entry.setActorUserId(actorUserId);
40	        entry.setActorUsername(actorUsername);
41	        entry.setRoleSnapshot(roleSnapshot);
42	        entry.setAction(action);
43	        entry.setEntityType(entityType);
44	        entry.setEntityId(entityId);
45	        entry.setRequestId(requestId);
46	        entry.setClientIp(clientIp);
47	        entry.setSuccess(success);
48	        entry.setMessage(message);
49	        entry.setOccurredAt(LocalDateTime.now());
50	        operationLogRepository.save(entry);
51	    }
52	
53	    @Transactional
54	    public void logDataAccess(
55	        Long actorUserId,
56	        String entityType,
57	        Long entityId,
58	        String accessType,
59	        String reason,
60	        String requestId
61	    ) {
62	        DataAccessLogEntity entry = new DataAccessLogEntity();
63	        entry.setActorUserId(actorUserId);
64	        entry.setEntityType(entityType);
65	        entry.setEntityId(entityId);
66	        entry.setAccessType(accessType);
67	        entry.setReason(reason);
68	        entry.setRequestId(requestId);
69	        entry.setOccurredAt(LocalDateTime.now());
70	        dataAccessLogRepository.save(entry);
71	    }
72	}
