29	    @ExceptionHandler(MethodArgumentNotValidException.class)
30	    public ResponseEntity<ApiErrorResponse> handleValidation(MethodArgumentNotValidException ex, HttpServletRequest request) {
31	        List<String> errors = ex.getBindingResult().getFieldErrors().stream()
32	            .map(err -> err.getField() + " " + err.getDefaultMessage())
33	            .collect(Collectors.toList());
34	        String message = errors.isEmpty() ? "Validation failed" : String.join("; ", errors);
35	        return error(HttpStatus.BAD_REQUEST, message, request);
36	    }
37	
38	    @ExceptionHandler(BindException.class)
39	    public ResponseEntity<ApiErrorResponse> handleBind(BindException ex, HttpServletRequest request) {
40	        List<String> errors = ex.getBindingResult().getFieldErrors().stream()
41	            .map(err -> err.getField() + " " + err.getDefaultMessage())
42	            .collect(Collectors.toList());
43	        String message = errors.isEmpty() ? "Binding failed" : String.join("; ", errors);
44	        return error(HttpStatus.BAD_REQUEST, message, request);
45	    }
46	
47	    @ExceptionHandler(IllegalArgumentException.class)
48	    public ResponseEntity<ApiErrorResponse> handleIllegalArgument(IllegalArgumentException ex, HttpServletRequest request) {
