50	    }
51	
52	    @ExceptionHandler(IllegalStateException.class)
53	    public ResponseEntity<ApiErrorResponse> handleIllegalState(IllegalStateException ex, HttpServletRequest request) {
54	        return error(HttpStatus.CONFLICT, ex.getMessage(), request);
55	    }
56	
57	    @ExceptionHandler({MethodArgumentTypeMismatchException.class, MissingServletRequestParameterException.class, HttpMessageNotReadableException.class})
58	    public ResponseEntity<ApiErrorResponse> handleRequestFormatting(Exception ex, HttpServletRequest request) {
59	        return error(HttpStatus.BAD_REQUEST, "Malformed request", request);
60	    }
61	
62	    @ExceptionHandler(AccessDeniedException.class)
63	    public ResponseEntity<ApiErrorResponse> handleAccessDenied(AccessDeniedException ex, HttpServletRequest request) {
