88	    private ResponseEntity<ApiErrorResponse> error(HttpStatus status, String message, HttpServletRequest request) {
89	        String traceId = resolveTraceId(request);
90	        ApiErrorResponse body = new ApiErrorResponse(
91	            OffsetDateTime.now().toString(),
92	            status.value(),
93	            status.getReasonPhrase(),
94	            message,
95	            request == null ? "" : request.getRequestURI(),
96	            traceId
97	        );
98	        return ResponseEntity.status(status).body(body);
99	    }
100	
101	    private String resolveTraceId(HttpServletRequest request) {
102	        if (request != null) {
103	            String correlation = request.getHeader("X-Correlation-Id");
104	            if (correlation != null && !correlation.isBlank()) {
105	                return correlation;
106	            }
107	            Object attr = request.getAttribute("traceId");
108	            if (attr instanceof String value && !value.isBlank()) {
109	                return value;
110	            }
111	        }
112	        String mdcTrace = MDC.get("traceId");
113	        return (mdcTrace == null || mdcTrace.isBlank()) ? "n/a" : mdcTrace;
114	    }
