111	    @Transactional
112	    public RecalculationResult recomputeStudentClass(Long studentId, Long classId, String reasonCode) {
113	        if (studentId == null || classId == null) {
114	            throw new IllegalArgumentException("studentId and classId are required");
115	        }
116	        if (!StringUtils.hasText(reasonCode)) {
117	            throw new IllegalArgumentException("reasonCode is required");
118	        }
119	
120	        CalculationContext context = resolveCalculationContext();
121	        List<GradeLedgerEntryEntity> ledger = gradeLedgerEntryRepository.findByStudentIdAndClassIdOrderByEnteredAtDesc(studentId, classId);
122	        if (ledger.isEmpty()) {
123	            throw new IllegalArgumentException("No ledger entries found for student/class");
124	        }
125	
126	        Map<String, GradeLedgerEntryEntity> latestByAssessment = new LinkedHashMap<>();
127	        for (GradeLedgerEntryEntity entry : ledger) {
128	            latestByAssessment.putIfAbsent(entry.getAssessmentKey(), entry);
129	        }
130	
131	        GradeRecalculationEntity recalculation = new GradeRecalculationEntity();
132	        recalculation.setStudentId(studentId);
133	        recalculation.setClassId(classId);
134	        recalculation.setTriggeredBy(currentUserId());
135	        recalculation.setTriggeredAt(LocalDateTime.now());
136	        recalculation.setScopeJson(toJson(Map.of("studentId", studentId, "classId", classId, "reasonCode", reasonCode)));
137	        recalculation.setDeterministicHash(deterministicHash(context.ruleVersion().getId(), latestByAssessment.values().stream().toList()));
138	        recalculation.setStatus("COMPLETED");
139	        GradeRecalculationEntity savedRecalc = gradeRecalculationRepository.save(recalculation);
140	
141	        List<RecalculationDelta> deltas = new ArrayList<>();
142	        for (GradeLedgerEntryEntity entry : latestByAssessment.values()) {
143	            GradeImpact recomputed = calculateImpact(context.ruleVersion(), entry.getRawScore(), entry.getMaxScore());
144	            Map<String, Object> previous = new LinkedHashMap<>();
145	            previous.put("gradeLetter", entry.getGradeLetter());
146	            previous.put("creditsEarned", entry.getCreditsEarned());
147	            previous.put("gpaPoints", entry.getGpaPoints());
148	            previous.put("ruleVersionId", entry.getRuleVersionId());
149	
150	            Map<String, Object> next = new LinkedHashMap<>();
151	            next.put("gradeLetter", recomputed.gradeLetter());
152	            next.put("creditsEarned", recomputed.creditsEarned());
153	            next.put("gpaPoints", recomputed.gpaImpact());
154	            next.put("ruleVersionId", context.ruleVersion().getId());
155	            Map<String, Object> delta = Map.of(
156	                "gradeChanged", !String.valueOf(entry.getGradeLetter()).equals(recomputed.gradeLetter()),
157	                "deltaCredits", recomputed.creditsEarned().subtract(entry.getCreditsEarned()).setScale(3, RoundingMode.HALF_UP),
158	                "deltaGpaPoints", recomputed.gpaImpact().subtract(entry.getGpaPoints()).setScale(3, RoundingMode.HALF_UP)
159	            );
160	
161	            GradeRecalculationDeltaEntity deltaEntity = new GradeRecalculationDeltaEntity();
162	            deltaEntity.setRecalculationId(savedRecalc.getId());
163	            deltaEntity.setGradeLedgerEntryId(entry.getId());
164	            deltaEntity.setPreviousResultJson(toJson(previous));
165	            deltaEntity.setNewResultJson(toJson(next));
166	            deltaEntity.setDeltaJson(toJson(delta));
167	            deltaEntity.setCreatedAt(LocalDateTime.now());
168	            gradeRecalculationDeltaRepository.save(deltaEntity);
169	
170	            deltas.add(new RecalculationDelta(entry.getId(), previous, next, delta));
171	        }
172	
173	        return new RecalculationResult(savedRecalc.getId(), savedRecalc.getDeterministicHash(), deltas);
174	    }
