176	    private void validateRequest(GradeEntryRequest request) {
177	        if (request.studentId() == null || request.classId() == null || !StringUtils.hasText(request.assessmentKey())) {
178	            throw new IllegalArgumentException("studentId, classId, assessmentKey are required");
179	        }
180	        if (request.rawScore() == null || request.maxScore() == null || request.maxScore().compareTo(BigDecimal.ZERO) <= 0) {
181	            throw new IllegalArgumentException("rawScore/maxScore must be valid and maxScore > 0");
182	        }
183	        if (request.rawScore().compareTo(BigDecimal.ZERO) < 0 || request.rawScore().compareTo(request.maxScore()) > 0) {
184	            throw new IllegalArgumentException("rawScore must be between 0 and maxScore");
185	        }
186	        String operation = normalizeOperationType(request.operationType());
187	        if (!OPERATION_TYPES.contains(operation)) {
188	            throw new IllegalArgumentException("Unsupported operation type");
189	        }
190	        if ("MANUAL_OVERRIDE".equals(operation)) {
191	            if (!StringUtils.hasText(request.reasonCode())) {
192	                throw new IllegalArgumentException("Immutable reason code is required for manual override");
193	            }
194	            OverrideReasonCodeEntity reason = overrideReasonCodeRepository.findByReasonCode(request.reasonCode().trim().toUpperCase(Locale.ROOT))
195	                .orElseThrow(() -> new IllegalArgumentException("Unknown reason code"));
196	            if (!reason.isImmutable()) {
197	                throw new IllegalArgumentException("Reason code must be immutable");
198	            }
199	        }
200	        if (("EDIT".equals(operation) || "MANUAL_OVERRIDE".equals(operation)) && request.previousEntryId() == null) {
201	            throw new IllegalArgumentException("previousEntryId is required for edit/manual override");
202	        }
203	    }
