231	    private GradeImpact calculateImpact(GradeRuleVersionEntity version, BigDecimal rawScore, BigDecimal maxScore) {
232	        Map<String, Object> json;
233	        try {
234	            json = objectMapper.readValue(version.getRuleJson(), new TypeReference<>() {
235	            });
236	        } catch (Exception ex) {
237	            throw new IllegalStateException("Invalid grade rule JSON", ex);
238	        }
239	
240	        BigDecimal percent = rawScore
241	            .multiply(BigDecimal.valueOf(100))
242	            .divide(maxScore, 6, RoundingMode.HALF_UP);
243	
244	        Map<String, Object> creditPolicy = asMap(json.get("creditPolicy"));
245	        BigDecimal baseCredits = asDecimal(creditPolicy.getOrDefault("baseCredits", BigDecimal.valueOf(3)));
246	        BigDecimal passingPercent = asDecimal(creditPolicy.getOrDefault("passingPercent", BigDecimal.valueOf(60)));
247	        boolean partialCreditEnabled = Boolean.TRUE.equals(creditPolicy.get("partialCreditEnabled"));
248	
249	        List<Map<String, Object>> gradingScale = asMapList(json.get("gradingScale"));
250	        gradingScale.sort(Comparator.comparing((Map<String, Object> m) -> asDecimal(m.get("minPercent"))).reversed());
251	
252	        String gradeLetter = "F";
253	        BigDecimal gpaPoint = BigDecimal.ZERO;
254	        for (Map<String, Object> row : gradingScale) {
255	            BigDecimal minPercent = asDecimal(row.get("minPercent"));
256	            if (percent.compareTo(minPercent) >= 0) {
257	                gradeLetter = String.valueOf(row.getOrDefault("grade", "F"));
258	                gpaPoint = asDecimal(row.getOrDefault("gpaPoints", BigDecimal.ZERO));
259	                break;
260	            }
261	        }
262	
263	        BigDecimal creditsEarned;
264	        if (percent.compareTo(passingPercent) >= 0) {
265	            creditsEarned = baseCredits;
266	        } else if (partialCreditEnabled) {
267	            BigDecimal ratio = percent.divide(passingPercent, 4, RoundingMode.HALF_UP);
268	            creditsEarned = baseCredits.multiply(ratio).setScale(3, RoundingMode.HALF_UP);
269	        } else {
270	            creditsEarned = BigDecimal.ZERO;
271	        }
272	
273	        BigDecimal gpaImpact = gpaPoint.multiply(creditsEarned).setScale(3, RoundingMode.HALF_UP);
274	        return new GradeImpact(
275	            percent.setScale(3, RoundingMode.HALF_UP),
276	            gradeLetter,
277	            creditsEarned.setScale(3, RoundingMode.HALF_UP),
278	            gpaImpact,
279	            null,
280	            null,
281	            null
282	        );
283	    }
