293	            current.gpaImpact(),
294	            rawScore.subtract(previous.getRawScore()).setScale(3, RoundingMode.HALF_UP),
295	            current.creditsEarned().subtract(previous.getCreditsEarned()).setScale(3, RoundingMode.HALF_UP),
296	            current.gpaImpact().subtract(previous.getGpaPoints()).setScale(3, RoundingMode.HALF_UP)
297	        );
298	    }
