304	    private String deterministicHash(Long ruleVersionId, List<GradeLedgerEntryEntity> entries) {
305	        try {
306	            StringBuilder source = new StringBuilder("rv=").append(ruleVersionId);
307	            for (GradeLedgerEntryEntity entry : entries) {
308	                source.append('|')
309	                    .append(entry.getId()).append(':')
310	                    .append(entry.getAssessmentKey()).append(':')
311	                    .append(entry.getRawScore()).append('/').append(entry.getMaxScore());
312	            }
313	            byte[] digest = MessageDigest.getInstance("SHA-256").digest(source.toString().getBytes(StandardCharsets.UTF_8));
314	            StringBuilder out = new StringBuilder();
315	            for (byte b : digest) {
316	                out.append(String.format("%02x", b));
317	            }
318	            return out.toString();
319	        } catch (Exception ex) {
320	            throw new IllegalStateException("Unable to compute recalculation hash", ex);
321	        }
322	    }
