340	    private static Map<String, Object> asMap(Object value) {
341	        return value instanceof Map<?, ?> map ? (Map<String, Object>) map : Map.of();
342	    }
343	
344	    @SuppressWarnings("unchecked")
345	    private static List<Map<String, Object>> asMapList(Object value) {
346	        return value instanceof List<?> list ? (List<Map<String, Object>>) list : List.of();
347	    }
348	
349	    private static BigDecimal asDecimal(Object value) {
350	        if (value == null) {
351	            return BigDecimal.ZERO;
352	        }
353	        if (value instanceof BigDecimal bigDecimal) {
354	            return bigDecimal;
355	        }
356	        if (value instanceof Number number) {
357	            return BigDecimal.valueOf(number.doubleValue());
358	        }
359	        return new BigDecimal(String.valueOf(value));
360	    }
