12	public class GovernanceAuditService {
13	
14	    private final ChangeHistoryRepository changeHistoryRepository;
15	    private final RecycleBinRepository recycleBinRepository;
16	    private final UserIdentityService userIdentityService;
17	    private final UserRepository userRepository;
18	    private final ObjectMapper objectMapper;
19	
20	    public GovernanceAuditService(
21	        ChangeHistoryRepository changeHistoryRepository,
22	        RecycleBinRepository recycleBinRepository,
23	        UserIdentityService userIdentityService,
24	        UserRepository userRepository,
25	        ObjectMapper objectMapper
26	    ) {
27	        this.changeHistoryRepository = changeHistoryRepository;
28	        this.recycleBinRepository = recycleBinRepository;
29	        this.userIdentityService = userIdentityService;
30	        this.userRepository = userRepository;
31	        this.objectMapper = objectMapper;
32	    }
33	
34	    @Transactional
35	    public void recordChange(String entityType, Long entityId, String operation, Object oldData, Object newData, String reasonCode) {
36	        ChangeHistoryEntity entity = new ChangeHistoryEntity();
37	        entity.setEntityType(entityType);
38	        entity.setEntityId(entityId);
39	        entity.setOperation(operation);
40	        entity.setChangedBy(currentUserId());
41	        entity.setChangedAt(LocalDateTime.now());
42	        entity.setOldData(toJson(oldData));
43	        entity.setNewData(toJson(newData));
44	        entity.setReasonCode(reasonCode);
45	        changeHistoryRepository.save(entity);
46	    }
47	
48	    @Transactional
49	    public RecycleBinEntity recordRecycle(String entityType, Long entityId, Object payload) {
50	        RecycleBinEntity entity = new RecycleBinEntity();
51	        entity.setEntityType(entityType);
52	        entity.setEntityId(entityId);
53	        entity.setDeletedBy(currentUserId());
54	        entity.setDeletedAt(LocalDateTime.now());
55	        entity.setPurgeAfter(LocalDateTime.now().plusDays(30));
56	        entity.setPayload(toJson(payload));
57	        entity.setRestored(false);
58	        return recycleBinRepository.save(entity);
59	    }
60	
61	    @Transactional
62	    public void markRestored(String entityType, Long entityId) {
63	        for (RecycleBinEntity entry : recycleBinRepository.findByRestoredFalseOrderByDeletedAtDesc()) {
64	            if (!entityType.equals(entry.getEntityType()) || !entityId.equals(entry.getEntityId())) {
65	                continue;
66	            }
67	            entry.setRestored(true);
68	            entry.setRestoredBy(currentUserId());
69	            entry.setRestoredAt(LocalDateTime.now());
70	            recycleBinRepository.save(entry);
71	            break;
72	        }
73	    }
74	
75	    private Long currentUserId() {
76	        return userIdentityService.resolveCurrentUserId().orElseGet(() -> userRepository.findIdByUsername("sysadmin").orElse(1L));
77	    }
78	
79	    private String toJson(Object source) {
80	        if (source == null) {
81	            return null;
82	        }
83	        try {
84	            return objectMapper.writeValueAsString(source);
85	        } catch (JsonProcessingException ex) {
86	            return "{\"serializationError\":\"" + ex.getOriginalMessage().replace("\"", "'") + "\"}";
87	        }
88	    }
89	}
