305	    public StudentTimelineView timeline(Long studentId, boolean allowUnmask) {
306	        StudentProfileEntity student = findActiveStudent(studentId);
307	        List<EnrollmentRecordEntity> enrollments = enrollmentRecordRepository.findByStudentIdAndDeletedAtIsNullOrderByEnrolledAtDesc(studentId);
308	        List<PaymentRecordEntity> payments = paymentRecordRepository.findByStudentIdOrderByRecordedAtDesc(studentId);
309	        List<InstructorCommentRecordEntity> comments = instructorCommentRecordRepository.findByStudentIdOrderByCreatedAtDesc(studentId);
310	        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
311	        if (isStudentPrincipal(authentication)) {
312	            comments = comments.stream().filter(comment -> "STUDENT_VISIBLE".equals(comment.getVisibility())).toList();
313	        }
314	        List<HomeworkAttachmentRecordEntity> attachments = homeworkAttachmentRecordRepository.findByStudentIdOrderByUploadedAtDesc(studentId);
315	
316	        Map<Long, CourseClassRefEntity> classMap = new HashMap<>();
317	        for (CourseClassRefEntity classEntity : courseClassRefRepository.findAll()) {
318	            classMap.put(classEntity.getId(), classEntity);
319	        }
320	
321	        List<Long> enrollmentIds = enrollments.stream().map(EnrollmentRecordEntity::getId).toList();
322	        List<StudentAttendanceEntity> attendance = enrollmentIds.isEmpty()
323	            ? List.of()
324	            : studentAttendanceRepository.findByEnrollmentIdInOrderByCreatedAtDesc(enrollmentIds);
325	
326	        Map<Long, ClassSessionRefEntity> sessionMap = new HashMap<>();
327	        for (ClassSessionRefEntity session : classSessionRefRepository.findAll()) {
328	            sessionMap.put(session.getId(), session);
329	        }
330	
331	        List<TimelineEvent> events = new ArrayList<>();
332	        for (EnrollmentRecordEntity enrollment : enrollments) {
333	            events.add(TimelineEvent.of(
334	                enrollment.getEnrolledAt(),
335	                "ENROLLMENT",
336	                classLabel(classMap, enrollment.getClassId()) + " - " + enrollment.getEnrollmentStatus()
337	            ));
338	        }
339	        for (PaymentRecordEntity payment : payments) {
340	            events.add(TimelineEvent.of(
341	                payment.getRecordedAt(),
342	                "PAYMENT",
343	                payment.getPaymentMethod() + " " + payment.getCurrencyCode() + " " + payment.getAmount()
344	            ));
345	        }
346	        for (StudentAttendanceEntity att : attendance) {
347	            ClassSessionRefEntity session = sessionMap.get(att.getClassSessionId());
348	            String detail = "Session " + (session == null ? att.getClassSessionId() : session.getSessionNo()) + " - " + att.getAttendanceStatus();
349	            events.add(TimelineEvent.of(att.getCreatedAt(), "ATTENDANCE", detail));
350	        }
351	        for (InstructorCommentRecordEntity comment : comments) {
352	            events.add(TimelineEvent.of(comment.getCreatedAt(), "COMMENT", comment.getVisibility() + " - " + comment.getCommentText()));
353	        }
354	        for (HomeworkAttachmentRecordEntity attachment : attachments) {
355	            events.add(TimelineEvent.of(
356	                attachment.getUploadedAt(),
357	                "HOMEWORK",
358	                attachment.getOriginalFileName() + " (" + attachment.getMimeType() + ")"
359	            ));
360	        }
361	        events.sort(Comparator.comparing(TimelineEvent::occurredAt).reversed());
362	
363	        StudentContactView contact = allowUnmask
364	            ? new StudentContactView(student.getContactEmail(), student.getContactPhone(), student.getContactAddress(), student.getEmergencyContact())
365	            : new StudentContactView(student.getMaskedEmail(), student.getMaskedPhone(), maskAddress(student.getContactAddress()), maskEmergency(student.getEmergencyContact()));
366	
367	        return new StudentTimelineView(student, contact, enrollments, payments, attendance, comments, attachments, events, classMap, sessionMap);
368	    }
