387	    public void assertCanAccessStudent(Authentication authentication, Long studentId) {
388	        if (authentication == null || !authentication.isAuthenticated()) {
389	            throw new AccessDeniedException("Authentication required");
390	        }
391	        if (hasAnyRole(authentication, "ROLE_SYSTEM_ADMIN", "ROLE_REGISTRAR_FINANCE_CLERK")) {
392	            return;
393	        }
394	
395	        if (isStudentPrincipal(authentication)) {
396	            StudentProfileEntity mine = resolveStudentForPrincipal(authentication);
397	            if (!mine.getId().equals(studentId)) {
398	                throw new AccessDeniedException("Cross-student access denied");
399	            }
400	            return;
401	        }
402	
403	        if (hasAnyRole(authentication, "ROLE_INSTRUCTOR")) {
404	            Long instructorUserId = userRepository.findIdByUsername(authentication.getName())
405	                .orElseThrow(() -> new AccessDeniedException("Instructor account is not linked to an active user"));
406	            if (instructorCanAccessStudent(instructorUserId, studentId)) {
407	                return;
408	            }
409	            throw new AccessDeniedException("Instructor can only access students in assigned classes");
410	        }
411	
412	        throw new AccessDeniedException("Role is not permitted to access student records");
413	    }
