517	    private static String maskEmail(String email) {
518	        if (!StringUtils.hasText(email) || !email.contains("@")) {
519	            return null;
520	        }
521	        String[] parts = email.split("@", 2);
522	        String local = parts[0];
523	        String masked = local.length() <= 2 ? "**" : local.substring(0, 2) + "***";
524	        return masked + "@" + parts[1];
525	    }
