582	    private static String sha256Hex(MultipartFile file) {
583	        try {
584	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
585	            byte[] hash = digest.digest(file.getBytes());
586	            return HexFormat.of().formatHex(hash);
587	        } catch (NoSuchAlgorithmException | IOException ex) {
588	            throw new IllegalStateException("Unable to compute checksum", ex);
589	        }
590	    }
