3	import com.instituteops.security.UserIdentityService;
4	import jakarta.servlet.FilterChain;
5	import jakarta.servlet.ServletException;
6	import jakarta.servlet.http.HttpServletRequest;
7	import jakarta.servlet.http.HttpServletResponse;
8	import java.io.IOException;
9	import java.util.Optional;
10	import java.util.UUID;
11	import java.util.stream.Collectors;
12	import org.springframework.security.core.Authentication;
13	import org.springframework.security.core.context.SecurityContextHolder;
14	import org.springframework.stereotype.Component;
15	import org.springframework.web.filter.OncePerRequestFilter;
16	
17	@Component
18	public class RequestAuditFilter extends OncePerRequestFilter {
19	
20	    private final AuditLogService auditLogService;
21	    private final UserIdentityService userIdentityService;
22	
23	    public RequestAuditFilter(AuditLogService auditLogService, UserIdentityService userIdentityService) {
24	        this.auditLogService = auditLogService;
25	        this.userIdentityService = userIdentityService;
26	    }
27	
28	    @Override
29	    protected boolean shouldNotFilter(HttpServletRequest request) {
30	        String path = request.getRequestURI();
31	        return path.startsWith("/css/") || path.startsWith("/js/") || path.startsWith("/images/") || path.equals("/favicon.ico");
32	    }
33	
34	    @Override
35	    protected void doFilterInternal(
36	        HttpServletRequest request,
37	        HttpServletResponse response,
38	        FilterChain filterChain
39	    ) throws ServletException, IOException {
40	        String requestId = Optional.ofNullable(request.getHeader("X-Request-ID"))
41	            .filter(v -> !v.isBlank())
42	            .orElse(UUID.randomUUID().toString());
43	        request.setAttribute("requestId", requestId);
44	
45	        try {
46	            filterChain.doFilter(request, response);
47	        } finally {
48	            Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
49	            String actorUsername = authentication == null ? "anonymous" : authentication.getName();
50	            String roles = authentication == null
51	                ? ""
52	                : authentication.getAuthorities().stream().map(a -> a.getAuthority()).sorted().collect(Collectors.joining(","));
53	
54	            Long actorUserId = userIdentityService.resolveCurrentUserId().orElse(null);
55	            boolean success = response.getStatus() < 400;
56	            String path = request.getRequestURI();
57	            String action = request.getMethod() + " " + path;
58	            String entityType = inferEntityType(path);
59	            Long entityId = inferEntityId(path);
60	
61	            auditLogService.logOperation(
62	                actorUserId,
63	                actorUsername,
64	                roles,
65	                action,
66	                entityType,
67	                entityId,
68	                requestId,
69	                request.getRemoteAddr(),
70	                success,
71	                "HTTP " + response.getStatus()
72	            );
73	
74	            if ("STUDENT".equals(entityType) && "GET".equalsIgnoreCase(request.getMethod())) {
75	                String accessType = hasUnmaskPrivilege(authentication) && "true".equalsIgnoreCase(request.getParameter("unmask"))
76	                    ? "UNMASKED_READ"
77	                    : "MASKED_READ";
78	                auditLogService.logDataAccess(actorUserId, entityType, entityId == null ? 0L : entityId, accessType, action, requestId);
79	            }
80	        }
81	    }
82	
83	    private static boolean hasUnmaskPrivilege(Authentication authentication) {
84	        if (authentication == null) {
85	            return false;
86	        }
87	        return authentication.getAuthorities().stream()
88	            .anyMatch(a -> "ROLE_SYSTEM_ADMIN".equals(a.getAuthority()) || "ROLE_REGISTRAR_FINANCE_CLERK".equals(a.getAuthority()));
89	    }
90	
91	    private static String inferEntityType(String path) {
92	        if (path.startsWith("/student") || path.startsWith("/api/students")) {
93	            return "STUDENT";
94	        }
95	        if (path.startsWith("/api/governance/students/")) {
96	            return "STUDENT";
97	        }
98	        if (path.startsWith("/inventory")) {
99	            return "INVENTORY";
100	        }
101	        if (path.startsWith("/procurement")) {
102	            return "PROCUREMENT";
103	        }
104	        if (path.startsWith("/store")) {
105	            return "GROUP_BUY";
106	        }
107	        return null;
108	    }
109	
110	    private static Long inferEntityId(String path) {
111	        if (path.startsWith("/api/governance/students/")) {
112	            String[] segments = path.split("/");
113	            if (segments.length >= 5) {
114	                try {
115	                    return Long.parseLong(segments[4]);
116	                } catch (NumberFormatException ignored) {
117	                    return null;
118	                }
119	            }
120	        }
121	        String[] segments = path.split("/");
122	        if (segments.length == 0) {
123	            return null;
124	        }
125	        String candidate = segments[segments.length - 1];
126	        try {
127	            return Long.parseLong(candidate);
128	        } catch (NumberFormatException ignored) {
129	            return null;
130	        }
131	    }
132	}
