ALTER TABLE data_access_logs DROP CHECK chk_data_access_type;
ALTER TABLE data_access_logs ADD CONSTRAINT chk_data_access_type
    CHECK (access_type IN (
        'READ', 'EXPORT', 'MASKED_READ', 'UNMASKED_READ',
        'GOVERNANCE_EXPORT', 'GOVERNANCE_IMPORT', 'GOVERNANCE_HISTORY_READ',
        'GOVERNANCE_PURGE', 'GOVERNANCE_RESTORE', 'GOVERNANCE_RECYCLE_READ',
        'GOVERNANCE_SCAN'
    ));

-- Fix 6: Grade ledger immutability — prevent UPDATE and DELETE via triggers.
CREATE TRIGGER trg_grade_ledger_no_update
    BEFORE UPDATE ON grade_ledger_entries
    FOR EACH ROW
BEGIN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Grade ledger entries are immutable and cannot be updated';
END;

CREATE TRIGGER trg_grade_ledger_no_delete
    BEFORE DELETE ON grade_ledger_entries
    FOR EACH ROW
BEGIN
    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Grade ledger entries are immutable and cannot be deleted';
END;
"}

