489	    private static int levenshtein(String a, String b) {
490	        int[][] dp = new int[a.length() + 1][b.length() + 1];
491	        for (int i = 0; i <= a.length(); i++) {
492	            dp[i][0] = i;
493	        }
494	        for (int j = 0; j <= b.length(); j++) {
495	            dp[0][j] = j;
496	        }
497	        for (int i = 1; i <= a.length(); i++) {
498	            for (int j = 1; j <= b.length(); j++) {
499	                int cost = a.charAt(i - 1) == b.charAt(j - 1) ? 0 : 1;
500	                dp[i][j] = Math.min(Math.min(dp[i - 1][j] + 1, dp[i][j - 1] + 1), dp[i - 1][j - 1] + cost);
501	            }
502	        }
503	        return dp[a.length()][b.length()];
504	    }

